sql:
SELECT title
FROM recipes
WHERE rating_average = 4.8 AND review_count = (SELECT MAX(review_count) FROM recipes);

SELECT COUNT(*) 
FROM reviews 
WHERE recipe_id = (SELECT recipe_id FROM reviews WHERE review_id = 0);

SELECT AVG(rating) AS average_rating
FROM reviews
WHERE recipe_id = (SELECT recipe_id FROM recipes WHERE title = 'Chocolate Chip Cookies');

SELECT title
FROM recipes
WHERE rating_average = (SELECT MAX(rating_average) FROM recipes);

SELECT review_count
FROM recipes
WHERE rating_average = (SELECT MAX(rating_average) FROM recipes);
